export type FeatureMachineStatus = "ready" | "loading" | "empty" | "error" | "portal" | "setup" | "streaming";

export interface FeatureWireframeMeta {
  visibleRegions: string[];
  selected: string;
  inputText: string;
  activePopup:
    | "none"
    | "menuSyntax"
    | "actionsDialog"
    | "shortcutRecorder"
    | "fileSearchActions"
    | "acpMention"
    | "acpModelSelector"
    | "acpHistory"
    | "acpActions"
    | "notesActions"
    | "notesSwitcher"
    | "notesConfirm"
    | "notesSearch";
  activePortal: "none" | "fileAttachment" | "acpAttachment" | "clipboardAttachment" | "notesAttachment";
  footerOwner:
    | "scriptList"
    | "rootFiles"
    | "menuSyntax"
    | "actionsDialog"
    | "shortcutRecorder"
    | "fileSearch"
    | "acpPortal"
    | "acpComposer"
    | "acpActions"
    | "acpHistory"
    | "acpSetup"
    | "protocol"
    | "mcp"
    | "sdkAutomation"
    | "builtins"
    | "quickTerminal"
    | "notes"
    | "notesAcp"
    | "notesBrowse"
    | "childSurface";
  status: FeatureMachineStatus;
  proof: string[];
}

export interface AuthoredStateNode {
  initial?: string;
  states?: Record<string, AuthoredStateNode>;
  on?: Record<string, string | { target?: string; actions?: string | string[]; guard?: string }>;
  meta?: {
    wireframe?: FeatureWireframeMeta;
  };
}

export interface AuthoredFeatureMachineConfig {
  id: string;
  version: "1";
  initial: string;
  context?: Record<string, unknown>;
  states: Record<string, AuthoredStateNode>;
  meta: {
    authored: true;
    featureId: string;
    slug: string;
    title: string;
    sourceFile: string;
    receipts: string[];
  };
}

function wf(
  visibleRegions: string[],
  selected: string,
  inputText: string,
  activePopup: FeatureWireframeMeta["activePopup"],
  activePortal: FeatureWireframeMeta["activePortal"],
  footerOwner: FeatureWireframeMeta["footerOwner"],
  status: FeatureMachineStatus,
  proof: string[]
) {
  return {
    wireframe: { visibleRegions, selected, inputText, activePopup, activePortal, footerOwner, status, proof }
  };
}

